Here you can download several files for a subject that you can run nway matching on. The pipeline can take in any number of input sessions, however, the input ophys data should be from the same imaging plane of the same subject. To specify your own file to use, set dandiset_id to be the dandiset id of the files you’re interested in. Also set input_dandi_filepaths to be a list of the filepaths on dandi of each file you’re interested in providing to Nway Matching. When accessing an embargoed dataset, set dandi_api_key to be your DANDI API key.

dandiset_id = "000336"
dandi_filepath_1 = "sub-621602/sub-621602_ses-1193555033-acq-1193675753_ophys.nwb"
dandi_filepath_2 = "sub-621602/sub-621602_ses-1194555869-acq-1194754135_ophys.nwb"
download_loc = "."

# some newer OpenScope files from Predictive Processing Community Project
# dandiset_id = "001768"
# dandi_filepath_1 = "sub-839909/sub-839909_ses-multiplane-ophys-839909-2026-02-20-12-53-27_ophys.nwb"
# dandi_filepath_2 = "sub-839909/sub-839909_ses-multiplane-ophys-839909-2026-02-26-15-11-01_ophys.nwb"

# here, specify the list dandi filepaths of the files you want to run cell matching on
# the subject ids should be the same, but the session ids should be different
input_dandi_filepaths = [dandi_filepath_1, dandi_filepath_2]



ios = [dandi_download_open(dandiset_id, filepath, download_loc) for filepath in input_dandi_filepaths]
nwbs = [io.read() for io in ios]



# since newer OpenScope NWBs have all planes, specify one here if necessary
# set plane_name = None if using older NWBs (one file per plane)
# plane_name = 'VISp_1'
plane_name = None




### Helpers to fetch fields from NWB files, which can be in different locations/formats in older vs newer NWBs

if plane_name is not None:
    # use these for newer OpenScope NWBs (all planes in one file)
    def get_avg_image(nwb):
        return np.array(nwb.processing[plane_name]["images"]["average_projection"])

    def get_roi_table(nwb):
        return nwb.processing[plane_name]["image_segmentation"]["roi_table"]

    def get_depth(nwb):
        return nwb.imaging_planes[plane_name].location.split()[3]
else:
    # use these for older OpenScope NWBs (one file per imaging plane)
    def get_avg_image(nwb):
        return np.array(nwb.processing["ophys"]["images"]["average_image"])

    def get_roi_table(nwb):
        return nwb.processing["ophys"]["image_segmentation"]["cell_specimen_table"]

    def get_depth(nwb):
        return nwb.lab_meta_data["metadata"].imaging_depth

# nway matching expects an integer id for each NWB, so we'll invent some
nwb_ids = {nwb.identifier: i for i, nwb in enumerate(nwbs)}
def get_nwb_id(nwb):
    return nwb_ids[nwb.identifier]

# these should be similar values, indicating that the images are from the same imaging plane
for nwb in nwbs:
    print(get_depth(nwb))

